// Color name mapping for variations
const COLOR_MAPPINGS = {
  // Reds
  'cardinal red': 'cardinal-red',
  'red': 'cardinal-red',
  
  // Grays
  'dark grey': 'dark-grey',
  'light grey': 'light-grey',
  'gray': 'gray',
  'grey': 'gray',
  'heather grey': 'heather-grey',
  'gray heather': 'gray-heather',
  'grey heather': 'gray-heather',
  
  // Blues
  'royal heather': 'royal-heather',
  'navy': 'navy',
  'classic navy': 'navy',
  
  // Greens
  'alpine green': 'alpine-green',
  'mint': 'mint',
  'sage': 'sage',
  
  // Special patterns
  'black camo': 'black-camo',
  'cotton candy': 'cotton-candy',
  'army heather': 'army-heather',
  
  // Natural tones
  'natural': 'natural',
  'bone': 'bone'
};

// Helper function to get garment image
export const getGarmentImage = (garmentType, color, side = 'front') => {
  const garment = GARMENT_IMAGES[garmentType];
  if (!garment) return null;
  
  // Normalize color name
  const normalizedColor = color.toLowerCase().trim();
  
  // Try color mapping first
  const mappedColor = COLOR_MAPPINGS[normalizedColor] || normalizedColor.replace(/\s+/g, '-');
  
  // Try exact match with mapped color
  if (garment[mappedColor] && garment[mappedColor][side]) {
    return garment[mappedColor][side];
  }
  
  // Try without dashes
  const noDashColor = mappedColor.replace(/-/g, '');
  if (garment[noDashColor] && garment[noDashColor][side]) {
    return garment[noDashColor][side];
  }
  
  // Fall back to default/main image
  if (garment[side] && garment[side].main) {
    return garment[side].main;
  }
  
  // Fall back to front if back not available
  if (side === 'back' && garment.front && garment.front.main) {
    return garment.front.main;
  }
  
  // Fall back to any available image
  const firstPart = Object.keys(garment).find(key => garment[key].main);
  if (firstPart && garment[firstPart].main) {
    return garment[firstPart].main;
  }
  
  return null;
};

// Get available colors for a garment type
export const getAvailableColors = (garmentType) => {
  const garment = GARMENT_IMAGES[garmentType];
  if (!garment) return [];
  
  return Object.keys(garment)
    .filter(key => key !== 'front' && key !== 'back' && key !== 'display')
    .map(slug => ({
      slug,
      name: slug.split('-').map(word => 
        word.charAt(0).toUpperCase() + word.slice(1)
      ).join(' ')
    }));
};
